from pydantic import BaseModel, field_validator, ValidationError
from typing import Optional
import re

# Define the authoritative product catalog as ground truth
PRODUCT_CATALOG = {
    "SKU-001": {"name": "Widget Pro", "price": 49.99, "return_days": 30},
    "SKU-002": {"name": "Gadget Lite", "price": 19.99, "return_days": 14},
}

class ProductResponse(BaseModel):
    sku: str
    product_name: str
    price_usd: float
    return_window_days: int
    summary: str

    @field_validator("sku")
    @classmethod
    def sku_must_exist(cls, v):
        if v not in PRODUCT_CATALOG:
            raise ValueError(f"Hallucinated SKU '{v}' not found in product catalog.")
        return v

    @field_validator("price_usd")
    @classmethod
    def price_must_match_catalog(cls, v, info):
        sku = info.data.get("sku")
        if sku and sku in PRODUCT_CATALOG:
            expected = PRODUCT_CATALOG[sku]["price"]
            if abs(v - expected) > 0.01:
                raise ValueError(
                    f"Hallucinated price ${v} does not match catalog price ${expected} for {sku}."
                )
        return v

    @field_validator("return_window_days")
    @classmethod
    def return_days_must_match_catalog(cls, v, info):
        sku = info.data.get("sku")
        if sku and sku in PRODUCT_CATALOG:
            expected = PRODUCT_CATALOG[sku]["return_days"]
            if v != expected:
                raise ValueError(
                    f"Hallucinated return window {v} days does not match catalog value {expected} days."
                )
        return v

def validate_agent_response(raw_response: dict) -> Optional[ProductResponse]:
    try:
        validated = ProductResponse(**raw_response)
        print("Response validated successfully.")
        return validated
    except ValidationError as e:
        print(f"Hallucination detected in agent response:\n{e}")
        return None

# Simulated agent output with hallucinated price and return window
agent_output = {
    "sku": "SKU-001",
    "product_name": "Widget Pro",
    "price_usd": 79.99,        # Hallucinated — should be 49.99
    "return_window_days": 60,  # Hallucinated — should be 30
    "summary": "The Widget Pro is our flagship product."
}

validate_agent_response(agent_output)
